import requests

KONG_ADMIN_URL = 'http://localhost:8001'  # Adjust this to your Kong Admin API URL

def create_service(service_name, service_url):
    response = requests.post(
        f'{KONG_ADMIN_URL}/services',
        json={
            'name': service_name,
            'url': service_url
        }
    )
    return response.json()

def create_route(service_name, route_paths):
    response = requests.post(
        f'{KONG_ADMIN_URL}/routes',
        json={
            'service': {'name': service_name},
            'paths': route_paths
        }
    )
    return response.json()

def create_upstream(upstream_name):
    response = requests.post(
        f'{KONG_ADMIN_URL}/upstreams',
        json={
            'Name': upstream_name
        }
    )
    return response.json()

def add_target_to_upstream(upstream_name, target_url, target_port):
    response = requests.post(
        f'{KONG_ADMIN_URL}/upstreams/{upstream_name}/targets',
        json={
            'target': target_url,
            'weight': target_port
        }
    )
    return response.json()

# Example usage
if __name__ == "__main__":
    service = create_service('my_service', 'http://my-service-url.com')
    route = create_route('my_service', ['/my-path'])
    upstream = create_upstream('my_upstream')
    target = add_target_to_upstream('my_upstream', 'my-target-url.com:80', 100)

    print('Service:', service)
    print('Route:', route)
    print('Upstream:', upstream)
    print('Target:', target)